import React, { useEffect, useState } from 'react';
import axios from 'axios';

function App() {
  const [sanPhams, setSanPhams] = useState([]);

  useEffect(() => {
    // Gọi API lấy dữ liệu từ Backend
    axios.get('http://localhost:5000/api/san-pham')
      .then(res => setSanPhams(res.data))
      .catch(err => console.error("Lỗi API:", err));
  }, []);

  return (
    <div style={{ padding: '20px', backgroundColor: '#f0f2f5', minHeight: '100vh' }}>
      <h1 style={{ textAlign: 'center' }}>🖥️ HỆ THỐNG BUILD PC TỰ CHỌN</h1>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(250px, 1fr))', gap: '20px', padding: '20px' }}>
        {sanPhams.map(item => (
          <div key={item._id} style={{ backgroundColor: '#fff', borderRadius: '10px', padding: '15px', boxShadow: '0 4px 8px rgba(0,0,0,0.1)', textAlign: 'center' }}>
            <img src={item.anh} alt={item.ten} style={{ width: '100%', height: '150px', objectFit: 'contain' }} />
            <h3 style={{ fontSize: '16px', margin: '10px 0' }}>{item.ten}</h3>
            <p style={{ color: '#e74c3c', fontWeight: 'bold' }}>{item.gia?.toLocaleString()} VNĐ</p>
            <button style={{ backgroundColor: '#007bff', color: '#fff', border: 'none', padding: '8px 15px', borderRadius: '5px', cursor: 'pointer' }}>Chọn linh kiện</button>
          </div>
        ))}
      </div>
    </div>
  );
}

export default App;
